import React, { useCallback, useMemo, useState } from 'react';
import {
  Input,
  Modal,
  Select,
  SearchTextInput,
  dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { WarehouseDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogMasterListRowMenu } from '../../../hooks/useCatalogMasterListRowMenu';
import {
  CatalogFormFooter,
  useCatalogListPaging,
  useCatalogTableBusy,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListMasterLinPageLayout,
  CatalogFormHistorySlot,
  CatalogListHeaderFilters,
  CatalogRowActionMenu,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { selectPlaceholderClass } from '../../../utils/selectField';
import { toCreateWarehousePayload, toUpdateWarehousePayload } from './warehousePayload';
import { WAREHOUSE_TYPE_OPTIONS, type WarehouseTypeValue } from './warehouseTypeOptions';

import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-danh-muc-kho';
const CATALOG_KIND = 'warehouses';

type FormErrors = Partial<Record<'code' | 'name' | 'warehouseType', string>>;

const DanhMucKhoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<WarehouseDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<WarehouseDto | null>(null);
  const [form, setForm] = useState<Partial<WarehouseDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getWarehouses({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải danh mục kho', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã kho';
    if (!form.name?.trim()) next.name = 'Nhập tên kho';
    if (!form.warehouseType?.trim()) next.warehouseType = 'Chọn loại kho';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true, warehouseType: 'Material' });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: WarehouseDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEditImpl = useCallback((row: WarehouseDto) => {
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const rowMenu = useCatalogMasterListRowMenu({
    testIdPrefix: TEST_ID,
    catalogKind: CATALOG_KIND,
    selection,
    openEdit: openEditImpl,
    openView,
  });

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateWarehouse(editing.id, toUpdateWarehousePayload(form));
      else await masterService.createWarehouse(toCreateWarehousePayload(form));
      markClean();
      dispatchAppToast(dispatch, { message: editing ? 'Cập nhật kho thành công' : 'Tạo kho thành công', type: 'success' });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateWarehouse(id, toUpdateWarehousePayload({ ...row, isActive: false }));
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} kho`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteWarehouse(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} kho`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
      <LinListFilterField testId={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </LinListFilterField>
    </CatalogListHeaderFilters>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={rowMenu.openEditWithPerm}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={rowMenu.toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{ title: 'Danh mục kho', titleIconClass: 'fas fa-warehouse' }}
        listTitle="Danh sách kho"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={filterBar}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu {...rowMenu.rowActionMenuProps} />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy kho phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={r => !isSharedCatalogReadOnly(r)}
            {...rowMenu.gridRowMenuProps}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem kho dùng chung' : editing ? 'Sửa kho' : 'Thêm kho'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã kho *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên kho *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-location`} style={{ gridColumn: '1 / -1' }}>
              <label className={styles.label}>Địa chỉ</label>
              <Input
                value={form.location ?? ''}
                disabled={viewOnlyShared}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, location: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-warehouseType`} style={{ gridColumn: '1 / -1' }}>
              <label className={styles.label}>Loại kho *</label>
              <Select
                value={form.warehouseType ?? ''}
                required
                disabled={viewOnlyShared}
                placeholder="— Chọn loại kho —"
                className={selectPlaceholderClass(form.warehouseType)}
                error={errors.warehouseType}
                options={WAREHOUSE_TYPE_OPTIONS}
                onChange={e => {
                  markDirty();
                  clearFieldError('warehouseType');
                  setForm(f => ({ ...f, warehouseType: e.target.value as WarehouseTypeValue }));
                }}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              location: form.location,
              warehouseType: form.warehouseType,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            historySlot={
              <CatalogFormHistorySlot
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                editing={editing ? { id: editing.id, code: editing.code } : null}
              />
            }
            saveDisabled={viewOnlyShared}
          />
        </div>
      </Modal>
    </>
  );
};

export default DanhMucKhoPage;
